import{_ as e,c as d,o,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"版本歷程: 功能演進 | opencode-agent-skills","description":"學習 OpenCode Agent Skills 外掛程式的版本演進歷程。本教學整理了從 v0.1.0 到 v0.6.4 的所有主要功能更新、Bug 修復、架構改進和重大變更說明。","frontmatter":{"title":"版本歷程: 功能演進 | opencode-agent-skills","sidebarTitle":"新版本做了什麼","subtitle":"版本歷程","description":"學習 OpenCode Agent Skills 外掛程式的版本演進歷程。本教學整理了從 v0.1.0 到 v0.6.4 的所有主要功能更新、Bug 修復、架構改進和重大變更說明。","tags":["版本更新","變更記錄","發布歷程"],"order":3},"headers":[],"relativePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/changelog/index.md"}'),l={name:"zh-tw/joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function r(i,t,s,n,c,h){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="版本歷程" tabindex="-1">版本歷程 <a class="header-anchor" href="#版本歷程" aria-label="Permalink to &quot;版本歷程&quot;">​</a></h1><p>本文檔記錄了 OpenCode Agent Skills 外掛程式的所有版本更新。透過版本歷程，你可以了解功能的演進路徑、修復的問題以及架構改進。</p><div class="tip custom-block"><p class="custom-block-title">當前版本</p><p>最新穩定版本是 <strong>v0.6.4</strong> (2026-01-20)</p></div><h2 id="版本時間線" tabindex="-1">版本時間線 <a class="header-anchor" href="#版本時間線" aria-label="Permalink to &quot;版本時間線&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本</th><th>發布日期</th><th>類型</th><th>主要內容</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>修復</td><td>YAML 解析、Claude v2 支援</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>改進</td><td>優化技能推薦提示</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>修復</td><td>技能名稱與目錄名分離</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>改進</td><td>避免重複推薦已載入技能</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>新功能</td><td>語意匹配、embedding 預先計算</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>改進</td><td>模糊比對建議、重構</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>改進</td><td>簡化安裝方式</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>改進</td><td>腳本遞迴搜尋</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>修復</td><td>符號連結處理</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>修復</td><td>保留代理模式</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>修復</td><td>模型切換問題</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>新功能</td><td>檔案列表功能</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>新功能</td><td>Superpowers 模式</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>初始</td><td>4 個工具、多位置發現</td></tr></tbody></table><h2 id="詳細變更記錄" tabindex="-1">詳細變更記錄 <a class="header-anchor" href="#詳細變更記錄" aria-label="Permalink to &quot;詳細變更記錄&quot;">​</a></h2><h3 id="v0-6-4-2026-01-20" tabindex="-1">v0.6.4 (2026-01-20) <a class="header-anchor" href="#v0-6-4-2026-01-20" aria-label="Permalink to &quot;v0.6.4 (2026-01-20)&quot;">​</a></h3><p><strong>修復</strong>：</p><ul><li>修復了技能多行描述的 YAML frontmatter 解析（支援 <code>|</code> 和 <code>&gt;</code> 區塊純量語法），透過用 <code>yaml</code> 程式庫替換自訂解析器</li><li>新增對 Claude 外掛程式 v2 格式的支援，<code>installed_plugins.json</code> 現在使用外掛程式安裝陣列而非單一物件</li></ul><p><strong>改進</strong>：</p><ul><li>Claude Code 外掛程式快取發現現在支援新的巢狀目錄結構（<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>）</li></ul><h3 id="v0-6-3-2025-12-16" tabindex="-1">v0.6.3 (2025-12-16) <a class="header-anchor" href="#v0-6-3-2025-12-16" aria-label="Permalink to &quot;v0.6.3 (2025-12-16)&quot;">​</a></h3><p><strong>改進</strong>：</p><ul><li>優化了技能評估提示，防止模型向使用者發送&quot;無需技能&quot;類訊息（使用者看不到隱藏的評估提示）</li></ul><h3 id="v0-6-2-2025-12-15" tabindex="-1">v0.6.2 (2025-12-15) <a class="header-anchor" href="#v0-6-2-2025-12-15" aria-label="Permalink to &quot;v0.6.2 (2025-12-15)&quot;">​</a></h3><p><strong>修復</strong>：</p><ul><li>技能驗證現在允許目錄名稱與 SKILL.md frontmatter 中的 <code>name</code> 不同。frontmatter 中的 <code>name</code> 是標準識別碼，目錄名稱僅用於組織。這符合 Anthropic Agent Skills 規範。</li></ul><h3 id="v0-6-1-2025-12-13" tabindex="-1">v0.6.1 (2025-12-13) <a class="header-anchor" href="#v0-6-1-2025-12-13" aria-label="Permalink to &quot;v0.6.1 (2025-12-13)&quot;">​</a></h3><p><strong>改進</strong>：</p><ul><li>動態技能推薦現在會追蹤每個會話已載入的技能，避免重複推薦已載入技能，減少冗餘提示和上下文使用</li></ul><h3 id="v0-6-0-2025-12-12" tabindex="-1">v0.6.0 (2025-12-12) <a class="header-anchor" href="#v0-6-0-2025-12-12" aria-label="Permalink to &quot;v0.6.0 (2025-12-12)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li><strong>語意技能匹配</strong>：在初始技能清單注入後，後續訊息會使用本地 embedding 與技能描述進行比對</li><li>新增 <code>@huggingface/transformers</code> 依賴用於本地 embedding 生成（量化版 all-MiniLM-L6-v2）</li><li>當訊息比對可用技能時，注入 3 步評估提示（EVALUATE → DECIDE → ACTIVATE），鼓勵載入技能（靈感來自 <a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a> 的<a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">部落格文章</a>）</li><li>磁碟快取 embedding 以實現低延遲比對（~/.cache/opencode-agent-skills/）</li><li>在 <code>session.deleted</code> 事件上清理會話</li></ul><h3 id="v0-5-0-2025-12-11" tabindex="-1">v0.5.0 (2025-12-11) <a class="header-anchor" href="#v0-5-0-2025-12-11" aria-label="Permalink to &quot;v0.5.0 (2025-12-11)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li>在所有工具（<code>use_skill</code>、<code>read_skill_file</code>、<code>run_skill_script</code>、<code>get_available_skills</code>）中新增&quot;你是否指...&quot;模糊比對建議</li></ul><p><strong>改進</strong>：</p><ul><li><strong>破壞性變更</strong>：將 <code>find_skills</code> 工具重新命名為 <code>get_available_skills</code>，意圖更明確</li><li><strong>內部</strong>：將程式庫重組為獨立模組（<code>claude.ts</code>、<code>skills.ts</code>、<code>tools.ts</code>、<code>utils.ts</code>、<code>superpowers.ts</code>），提高可維護性</li><li><strong>內部</strong>：透過刪除 AI 生成的註解和不必要的程式碼，提高程式碼品質</li></ul><h3 id="v0-4-1-2025-12-08" tabindex="-1">v0.4.1 (2025-12-08) <a class="header-anchor" href="#v0-4-1-2025-12-08" aria-label="Permalink to &quot;v0.4.1 (2025-12-08)&quot;">​</a></h3><p><strong>改進</strong>：</p><ul><li>安裝方式現在透過 OpenCode 設定使用 npm 套件，而非 git clone + 符號連結</li></ul><p><strong>移除</strong>：</p><ul><li>移除了 <code>INSTALL.md</code>（簡化安裝後不再需要）</li></ul><h3 id="v0-4-0-2025-12-05" tabindex="-1">v0.4.0 (2025-12-05) <a class="header-anchor" href="#v0-4-0-2025-12-05" aria-label="Permalink to &quot;v0.4.0 (2025-12-05)&quot;">​</a></h3><p><strong>改進</strong>：</p><ul><li>腳本發現現在遞迴搜尋整個技能目錄（最大深度 10），而非僅根目錄和 <code>scripts/</code> 子目錄</li><li>腳本現在透過相對路徑（如 <code>tools/build.sh</code>）而非基本名稱識別</li><li>在 <code>read_skill_file</code>、<code>run_skill_script</code> 和 <code>use_skill</code> 工具中將 <code>skill_name</code> 參數重新命名為 <code>skill</code></li><li>在 <code>run_skill_script</code> 工具中將 <code>script_name</code> 參數重新命名為 <code>script</code></li></ul><h3 id="v0-3-3-2025-12-02" tabindex="-1">v0.3.3 (2025-12-02) <a class="header-anchor" href="#v0-3-3-2025-12-02" aria-label="Permalink to &quot;v0.3.3 (2025-12-02)&quot;">​</a></h3><p><strong>修復</strong>：</p><ul><li>透過使用 <code>fs.stat</code> 修復了檔案和目錄偵測以正確處理符號連結</li></ul><h3 id="v0-3-2-2025-11-30" tabindex="-1">v0.3.2 (2025-11-30) <a class="header-anchor" href="#v0-3-2-2025-11-30" aria-label="Permalink to &quot;v0.3.2 (2025-11-30)&quot;">​</a></h3><p><strong>修復</strong>：</p><ul><li>在會話開始時注入合成訊息時保留代理模式</li></ul><h3 id="v0-3-1-2025-11-28" tabindex="-1">v0.3.1 (2025-11-28) <a class="header-anchor" href="#v0-3-1-2025-11-28" aria-label="Permalink to &quot;v0.3.1 (2025-11-28)&quot;">​</a></h3><p><strong>修復</strong>：</p><ul><li>透過在 <code>noReply</code> 操作中明確傳遞目前模型，修復了使用技能工具時的意外模型切換（針對 opencode issue #4475 的暫時方案）</li></ul><h3 id="v0-3-0-2025-11-27" tabindex="-1">v0.3.0 (2025-11-27) <a class="header-anchor" href="#v0-3-0-2025-11-27" aria-label="Permalink to &quot;v0.3.0 (2025-11-27)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li>在 <code>use_skill</code> 輸出中新增檔案列表</li></ul><h3 id="v0-2-0-2025-11-26" tabindex="-1">v0.2.0 (2025-11-26) <a class="header-anchor" href="#v0-2-0-2025-11-26" aria-label="Permalink to &quot;v0.2.0 (2025-11-26)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li>新增 Superpowers 模式支援</li><li>新增發布證明</li></ul><h3 id="v0-1-0-2025-11-26" tabindex="-1">v0.1.0 (2025-11-26) <a class="header-anchor" href="#v0-1-0-2025-11-26" aria-label="Permalink to &quot;v0.1.0 (2025-11-26)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li>新增 <code>use_skill</code> 工具，將技能內容載入到上下文</li><li>新增 <code>read_skill_file</code> 工具，讀取技能目錄中的支援檔案</li><li>新增 <code>run_skill_script</code> 工具，從技能目錄執行腳本</li><li>新增 <code>find_skills</code> 工具，搜尋並列出可用技能</li><li>新增多位置技能發現（專案級、使用者級和 Claude 相容位置）</li><li>新增符合 Anthropic Agent Skills Spec v1.0 的 frontmatter 驗證</li><li>新增會話開始和上下文壓縮後的自動技能清單注入</li></ul><p><strong>新貢獻者</strong>：</p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (維護者)</li></ul><h2 id="功能演進概覽" tabindex="-1">功能演進概覽 <a class="header-anchor" href="#功能演進概覽" aria-label="Permalink to &quot;功能演進概覽&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>引入版本</th><th>演進路徑</th></tr></thead><tbody><tr><td>4 個基礎工具</td><td>v0.1.0</td><td>v0.5.0 新增模糊比對</td></tr><tr><td>多位置技能發現</td><td>v0.1.0</td><td>v0.4.1 簡化安裝、v0.6.4 支援 Claude v2</td></tr><tr><td>上下文自動注入</td><td>v0.1.0</td><td>v0.3.0 新增檔案列表、v0.6.1 避免重複推薦</td></tr><tr><td>Superpowers 模式</td><td>v0.2.0</td><td>持續穩定</td></tr><tr><td>腳本遞迴搜尋</td><td>v0.4.0</td><td>v0.3.3 修復符號連結</td></tr><tr><td>語意比對推薦</td><td>v0.6.0</td><td>v0.6.1 避免重複、v0.6.3 優化提示</td></tr><tr><td>模糊比對建議</td><td>v0.5.0</td><td>持續穩定</td></tr></tbody></table><h2 id="重大變更說明" tabindex="-1">重大變更說明 <a class="header-anchor" href="#重大變更說明" aria-label="Permalink to &quot;重大變更說明&quot;">​</a></h2><h3 id="v0-6-0-語意匹配功能" tabindex="-1">v0.6.0：語意匹配功能 <a class="header-anchor" href="#v0-6-0-語意匹配功能" aria-label="Permalink to &quot;v0.6.0：語意匹配功能&quot;">​</a></h3><p>引入了基於本地 embedding 的語意比對能力，讓 AI 能夠根據使用者訊息內容自動推薦相關技能，無需使用者手動記憶技能名稱。</p><ul><li><strong>技術細節</strong>：使用 HuggingFace 的 <code>all-MiniLM-L6-v2</code> 模型（q8 量化）</li><li><strong>快取機制</strong>：embedding 結果快取到 <code>~/.cache/opencode-agent-skills/</code>，提升後續比對速度</li><li><strong>比對流程</strong>：使用者訊息 → embedding → 與技能描述計算餘弦相似度 → Top 5 推薦（閾值 0.35）</li></ul><h3 id="v0-5-0-重構與工具重新命名" tabindex="-1">v0.5.0：重構與工具重新命名 <a class="header-anchor" href="#v0-5-0-重構與工具重新命名" aria-label="Permalink to &quot;v0.5.0：重構與工具重新命名&quot;">​</a></h3><p>程式碼架構重構為模組化設計，工具命名更加清晰：</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-腳本發現機制升級" tabindex="-1">v0.4.0：腳本發現機制升級 <a class="header-anchor" href="#v0-4-0-腳本發現機制升級" aria-label="Permalink to &quot;v0.4.0：腳本發現機制升級&quot;">​</a></h3><p>腳本發現從&quot;僅根目錄 + scripts/&quot;升級為&quot;遞迴搜尋整個技能目錄&quot;（最大深度 10），支援更靈活的腳本組織方式。</p><h3 id="v0-2-0-superpowers-整合" tabindex="-1">v0.2.0：Superpowers 整合 <a class="header-anchor" href="#v0-2-0-superpowers-整合" aria-label="Permalink to &quot;v0.2.0：Superpowers 整合&quot;">​</a></h3><p>新增對 Superpowers 工作流程模式的支援，需要安裝 <code>using-superpowers</code> 技能並設定環境變數 <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code>。</p><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>目前版本號</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>版本歷程</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>關鍵版本資訊</strong>：</p><ul><li><code>v0.6.4</code>：目前版本 (2026-01-20)</li><li><code>v0.6.0</code>：語意比對引入 (2025-12-12)</li><li><code>v0.5.0</code>：重構版本 (2025-12-11)</li><li><code>v0.1.0</code>：初始版本 (2025-11-26)</li></ul></details>',72)])])}const v=e(l,[["render",r]]);export{p as __pageData,v as default};
